                OutputFormat::Json => {
                    println!("{}", serde_json::json!({"success": true}));
                }
            }
        }

        ClobCommand::Notifications => {
            let client = auth::authenticated_clob_client(private_key, signature_type).await?;
            let result = client.notifications().await?;
