fn prompt(msg: &str) -> Result<String> {
    print!("{msg}");
    io::stdout().flush()?;
    let mut input = String::new();
    io::stdin().lock().read_line(&mut input)?;
    Ok(input.trim().to_string())
}

fn prompt_yn(msg: &str, default: bool) -> Result<bool> {
    let hint = if default { "Y/n" } else { "y/N" };
    let input = prompt(&format!("{msg} [{hint}] "))?;
    Ok(match input.to_lowercase().as_str() {
        "y" | "yes" => true,
        "n" | "no" => false,
        _ => default,
    })
}

fn step_header(n: u8, total: u8, label: &str) {
    println!("  [{n}/{total}] {label}");
    println!("  {}", "─".repeat(label.len() + 6));
}

pub fn execute() -> Result<()> {
    print_banner();

    let total = 4;

    step_header(1, total, "Wallet");

    let address = if config::config_exists() {
        let (key, source) = config::resolve_key(None);
        if let Some(k) = &key
            && let Ok(signer) = LocalSigner::from_str(k)
        {
            let addr = signer.address();
            println!("  ✓ Wallet already configured ({})", source.label());
            println!("    Address: {addr}");
            println!();

            if !prompt_yn("  Reconfigure wallet?", false)? {
                finish_setup(addr)?;
                return Ok(());
            }
            println!();
        }
        setup_wallet()?
    } else {
        setup_wallet()?
    };

    println!();

    finish_setup(address)
}

fn setup_wallet() -> Result<Address> {
    let has_key = prompt_yn("  Do you have an existing private key?", false)?;

    let (address, key_hex) = if has_key {
        let key = prompt("  Enter private key: ")?;
        let normalized = normalize_key(&key);
        let signer = LocalSigner::from_str(&normalized)
            .context("Invalid private key")?
            .with_chain_id(Some(POLYGON));
        (signer.address(), normalized)
    } else {
        let signer = LocalSigner::random().with_chain_id(Some(POLYGON));
        let address = signer.address();
        let bytes = signer.credential().to_bytes();
        let mut hex = String::with_capacity(2 + bytes.len() * 2);
        hex.push_str("0x");
        for b in &bytes {
            write!(hex, "{b:02x}").unwrap();
        }
        (address, hex)
    };

    config::save_wallet(&key_hex, POLYGON, config::DEFAULT_SIGNATURE_TYPE)?;

    if has_key {
        println!("  ✓ Wallet imported");
    } else {
        println!("  ✓ Wallet created");
    }
    println!("    Address: {address}");
    println!("    Config:  {}", config::config_path()?.display());

    if !has_key {
        println!();
        println!("  ⚠ Back up your private key from the config file.");
        println!("    If lost, your funds cannot be recovered.");
    }

    Ok(address)
}

fn finish_setup(address: Address) -> Result<()> {
    let total = 4;

    step_header(2, total, "Proxy Wallet");

    let proxy = derive_proxy_wallet(address, POLYGON);
    match proxy {
        Some(proxy) => {
            println!("  ✓ Proxy wallet derived");
            println!("    Proxy: {proxy}");
            println!("    Deposit USDC to this address to start trading.");
        }
        None => {
            println!("  ✗ Could not derive proxy wallet");
            println!("    You may need to use --signature-type eoa");
        }
    }

    println!();

    step_header(3, total, "Fund Wallet");

    let deposit_addr = proxy.unwrap_or(address);
    println!("  ○ Deposit USDC to your wallet to start trading");
    println!("    Run: polymarket bridge deposit {deposit_addr}");
    println!("    Or transfer USDC directly on Polygon");

    println!();

    step_header(4, total, "Approve Contracts");

    println!("  Run `polymarket approve set` to approve contracts for trading.");
    println!("  Or `polymarket approve check` to see current approval status.");

    println!();
    println!("  ────────────────────────────────────");
    println!("  ✓ Setup complete! You're ready to go.");
    println!();
    println!("  Next steps:");
    println!("    polymarket shell              Interactive mode");
    println!("    polymarket markets list        Browse markets");
    println!("    polymarket clob book <token>   View order book");
    println!();

    Ok(())
}
use std::env;
use std::fs;
use std::process::Command;

use anyhow::{Context, bail};

const REPO: &str = "Polymarket/polymarket-cli";
const BINARY: &str = "polymarket";

pub fn execute() -> anyhow::Result<()> {
    let current_version = env!("CARGO_PKG_VERSION");
    println!("Current version: v{current_version}");
    println!("Checking for updates...");

    let latest_tag = get_latest_tag()?;
    let latest_version = latest_tag.trim_start_matches('v');

    if latest_version == current_version {
        println!("Already up to date.");
        return Ok(());
    }

    println!("New version available: {latest_tag}");

    let target = detect_target()?;
    let url = format!(
        "https://github.com/{REPO}/releases/download/{latest_tag}/{BINARY}-{latest_tag}-{target}.tar.gz"
    );

    let current_exe = env::current_exe().context("Failed to determine current executable path")?;

    let tmpdir = tempdir()?;
    let tarball = format!("{tmpdir}/{BINARY}.tar.gz");

    let tarball_name = format!("{BINARY}-{latest_tag}-{target}.tar.gz");
    let checksums_url =
        format!("https://github.com/{REPO}/releases/download/{latest_tag}/checksums.txt");

    println!("Downloading {latest_tag} ({target})...");

    let status = Command::new("curl")
        .args(["-sSfL", "-o", &tarball, &url])
        .status()
        .context("Failed to run curl")?;
    if !status.success() {
        bail!("Download failed (HTTP error)");
    }

    let checksums_file = format!("{tmpdir}/checksums.txt");
    let status = Command::new("curl")
        .args(["-sSfL", "-o", &checksums_file, &checksums_url])
        .status()
        .context("Failed to download checksums")?;
    if !status.success() {
        bail!("Failed to download checksums.txt — cannot verify integrity");
    }

    verify_checksum(&tarball, &checksums_file, &tarball_name)?;

    let status = Command::new("tar")
        .args(["xzf", &tarball, "-C", &tmpdir])
        .status()
        .context("Failed to extract archive")?;
    if !status.success() {
        bail!("Failed to extract archive");
    }

    let new_binary = format!("{tmpdir}/{BINARY}");

    // Replace the current binary
    let exe_path = current_exe.to_str().context("Non-UTF8 executable path")?;
    let backup = format!("{exe_path}.bak");

    // Move current binary to backup, move new binary in, then remove backup
    fs::rename(exe_path, &backup)
        .or_else(|_| sudo_mv(exe_path, &backup))
        .context("Failed to replace binary (try running with sudo)")?;

    if let Err(e) = fs::rename(&new_binary, exe_path).or_else(|_| sudo_mv(&new_binary, exe_path)) {
        // Restore backup on failure
        let _ = fs::rename(&backup, exe_path);
        return Err(e).context("Failed to install new binary");
    }

    // Set executable permission
    #[cfg(unix)]
    {
        use std::os::unix::fs::PermissionsExt;
        let _ = fs::set_permissions(exe_path, fs::Permissions::from_mode(0o755));
    }

    let _ = fs::remove_file(&backup);
    let _ = fs::remove_dir_all(&tmpdir);

    println!("Updated to {latest_tag}");
    Ok(())
}

fn get_latest_tag() -> anyhow::Result<String> {
    let output = Command::new("curl")
        .args([
            "-sSf",
            &format!("https://api.github.com/repos/{REPO}/releases/latest"),
        ])
        .output()
        .context("Failed to check for latest release")?;

    if !output.status.success() {
        bail!("Failed to fetch latest release info from GitHub");
    }

    let body = String::from_utf8_lossy(&output.stdout);
    let json: serde_json::Value =
        serde_json::from_str(&body).context("Failed to parse GitHub API response")?;

    json["tag_name"]
        .as_str()
        .map(String::from)
        .context("No tag_name in release response")
}

fn detect_target() -> anyhow::Result<&'static str> {
    let os = std::env::consts::OS;
    let arch = std::env::consts::ARCH;

    match (os, arch) {
        ("macos", "x86_64") => Ok("x86_64-apple-darwin"),
        ("macos", "aarch64") => Ok("aarch64-apple-darwin"),
        ("linux", "x86_64") => Ok("x86_64-unknown-linux-gnu"),
        ("linux", "aarch64") => Ok("aarch64-unknown-linux-gnu"),
        _ => bail!("Unsupported platform: {os}/{arch}"),
    }
}

fn tempdir() -> anyhow::Result<String> {
    let output = Command::new("mktemp")
        .args(["-d"])
        .output()
        .context("Failed to create temp directory")?;
    if !output.status.success() {
        bail!("mktemp failed");
    }
    Ok(String::from_utf8_lossy(&output.stdout).trim().to_string())
}

fn verify_checksum(
    file_path: &str,
    checksums_file: &str,
    expected_name: &str,
) -> anyhow::Result<()> {
    let checksums = fs::read_to_string(checksums_file).context("Failed to read checksums.txt")?;

    let expected_hash = checksums
        .lines()
        .find_map(|line| {
            let mut parts = line.split_whitespace();
            let hash = parts.next()?;
            let name = parts.next()?;
            if name == expected_name || name.trim_start_matches("./") == expected_name {
                Some(hash.to_string())
            } else {
                None
            }
        })
        .context(format!(
            "No checksum found for {expected_name} in checksums.txt"
        ))?;

    let output = Command::new("shasum")
        .args(["-a", "256", file_path])
        .output()
        .or_else(|_| Command::new("sha256sum").arg(file_path).output())
        .context("Failed to compute SHA256 (need shasum or sha256sum)")?;

    if !output.status.success() {
        bail!("Failed to compute SHA256 of downloaded file");
    }

    let actual_hash = String::from_utf8_lossy(&output.stdout)
        .split_whitespace()
        .next()
        .unwrap_or("")
        .to_string();

    if actual_hash != expected_hash {
        bail!(
            "Checksum mismatch!\n  Expected: {expected_hash}\n  Got:      {actual_hash}\n\nThe downloaded binary may have been tampered with. Aborting."
        );
    }

    println!("Checksum verified.");
    Ok(())
}

fn sudo_mv(from: &str, to: &str) -> std::io::Result<()> {
    let status = Command::new("sudo").args(["mv", from, to]).status()?;
    if status.success() {
        Ok(())
    } else {
        Err(std::io::Error::new(
            std::io::ErrorKind::PermissionDenied,
            "sudo mv failed",
        ))
    }
}

