import type { ApiKeyCreds, Chain, L1PolyHeader, L2HeaderArgs, L2PolyHeader, L2WithBuilderHeader } from "../types.ts";
import type { BuilderHeaderPayload } from "@polymarket/builder-signing-sdk";

export const createL1Headers = async (
    signer: Wallet | JsonRpcSigner,
    chainId: Chain,
    nonce?: number,
    timestamp?: number,
): Promise<L1PolyHeader> => {
    let ts = Math.floor(Date.now() / 1000);
    if (timestamp !== undefined) {
        ts = timestamp;
    }
    let n = 0; // Default nonce is 0
    if (nonce !== undefined) {
        n = nonce;
    }

    const sig = await buildClobEip712Signature(signer, chainId, ts, n);
    const address = await signer.getAddress();

    const headers = {
        POLY_ADDRESS: address,
        POLY_SIGNATURE: sig,
        POLY_TIMESTAMP: `${ts}`,
        POLY_NONCE: `${n}`,
    };
    return headers;
};

export const createL2Headers = async (
    signer: Wallet | JsonRpcSigner,
    creds: ApiKeyCreds,
    l2HeaderArgs: L2HeaderArgs,
    timestamp?: number,
): Promise<L2PolyHeader> => {
    let ts = Math.floor(Date.now() / 1000);
    if (timestamp !== undefined) {
        ts = timestamp;
    }
    const address = await signer.getAddress();

    const sig = await buildPolyHmacSignature(
        creds.secret,
        ts,
        l2HeaderArgs.method,
        l2HeaderArgs.requestPath,
        l2HeaderArgs.body,
    );

    const headers = {
        POLY_ADDRESS: address,
        POLY_SIGNATURE: sig,
        POLY_TIMESTAMP: `${ts}`,
        POLY_API_KEY: creds.key,
        POLY_PASSPHRASE: creds.passphrase,
    };

    return headers;
};

export const injectBuilderHeaders = (
    l2Header: L2PolyHeader,
    builderHeaders: BuilderHeaderPayload,
): L2WithBuilderHeader => ({
    ...l2Header,
    ...builderHeaders,
}) as L2WithBuilderHeader;

function replaceAll(s: string, search: string, replace: string) {
    return s.split(search).join(replace);
}

/**
 * Converts base64 string to ArrayBuffer
 */
function base64ToArrayBuffer(base64: string): ArrayBuffer {
    const sanitizedBase64 = base64
        // Convert base64url to base64 – some secrets routinely come in as base64url: https://stackoverflow.com/q/5234581
        .replace(/-/g, "+")
        .replace(/_/g, "/")
        // Remove any non-base64 characters, for backwards compatibility with Node.js Buffer.from()
        .replace(/[^A-Za-z0-9+/=]/g, "");
    const binaryString = atob(sanitizedBase64);
    const bytes = new Uint8Array(binaryString.length);
    for (let i = 0; i < binaryString.length; i++) {
        bytes[i] = binaryString.charCodeAt(i);
    }
    return bytes.buffer;
}

/**
 * Converts ArrayBuffer to base64 string
 */
function arrayBufferToBase64(buffer: ArrayBuffer): string {
    const bytes = new Uint8Array(buffer);
    let binary = "";
    for (let i = 0; i < bytes.byteLength; i++) {
        binary += String.fromCharCode(bytes[i]);
    }
    return btoa(binary);
}

/**
 * Builds the canonical Polymarket CLOB HMAC signature
 * @param signer
 * @param key
 * @param secret
 * @param passphrase
 * @returns string
 */
export const buildPolyHmacSignature = async (
    secret: string,
    timestamp: number,
    method: string,
    requestPath: string,
    body?: string,
): Promise<string> => {
    let message = timestamp + method + requestPath;
    if (body !== undefined) {
        message += body;
    }

    // Import the secret key from base64
    const keyData = base64ToArrayBuffer(secret);
    const cryptoKey = await globalThis.crypto.subtle.importKey(
        "raw",
        keyData,
        { name: "HMAC", hash: "SHA-256" },
        false,
        ["sign"],
    );

    // Sign the message
    const messageBuffer = new TextEncoder().encode(message);
    const signatureBuffer = await globalThis.crypto.subtle.sign("HMAC", cryptoKey, messageBuffer);
    const sig = arrayBufferToBase64(signatureBuffer);

    // NOTE: Must be url safe base64 encoding, but keep base64 "=" suffix
    // Convert '+' to '-'
    // Convert '/' to '_'
    const sigUrlSafe = replaceAll(replaceAll(sig, "+", "-"), "/", "_");
    return sigUrlSafe;
};

import type { Wallet } from "@ethersproject/wallet";
import type { JsonRpcSigner } from "@ethersproject/providers";
import { MSG_TO_SIGN } from "./constants.ts";
import type { Chain } from "../types.ts";

/**
 * Builds the canonical Polymarket CLOB EIP712 signature
 * @param signer
 * @param ts
 * @returns string
 */
export const buildClobEip712Signature = async (
    signer: Wallet | JsonRpcSigner,
    chainId: Chain,
    timestamp: number,
    nonce: number,
): Promise<string> => {
    const address = await signer.getAddress();
    const ts = `${timestamp}`;

    const domain = {
        name: "ClobAuthDomain",
        version: "1",
        chainId: chainId,
    };

    const types = {
        ClobAuth: [
            { name: "address", type: "address" },
            { name: "timestamp", type: "string" },
            { name: "nonce", type: "uint256" },
            { name: "message", type: "string" },
        ],
    };
    const value = {
        address,
        timestamp: ts,
        nonce,
        message: MSG_TO_SIGN,
    };
    // eslint-disable-next-line no-underscore-dangle
    const sig = await signer._signTypedData(domain, types, value);
    return sig;
};

export const CLOB_DOMAIN_NAME = "ClobAuthDomain";
export const CLOB_VERSION = "1";
export const MSG_TO_SIGN = "This message attests that I control the given wallet";

export const CLOB_DOMAIN = {
    name: CLOB_DOMAIN_NAME,
    version: CLOB_VERSION,
    chainId: 1,
};

export const CLOB_TYPES = {
    ClobAuth: [
        { name: "address", type: "address" },
        { name: "timestamp", type: "string" },
        { name: "message", type: "string" },
    ],
};

import type { Wallet } from "@ethersproject/wallet";
import type { JsonRpcSigner } from "@ethersproject/providers";
import { SignatureType } from "@polymarket/order-utils";
import type { SignedOrder } from "@polymarket/order-utils";
import { createMarketOrder, createOrder } from "./helpers.ts";
import type { Chain, CreateOrderOptions, UserMarketOrder, UserOrder } from "../types.ts";

export class OrderBuilder {
    readonly signer: Wallet | JsonRpcSigner;

    readonly chainId: Chain;

    // Signature type used sign orders, defaults to EOA type
    readonly signatureType: SignatureType;

    // Address which holds funds to be used.
    // Used for Polymarket proxy wallets and other smart contract wallets
    // If not provided, funderAddress is the signer address
    readonly funderAddress?: string;

    /**
     * Optional function to dynamically resolve the signer.
     * If provided, this function will be called to obtain a fresh signer instance
     * (e.g., for smart contract wallets or when the signer may change).
     * Should return a Wallet or JsonRpcSigner, or a Promise resolving to one.
     * If not provided, the static `signer` property is used.
     */
    private getSigner?: () => Promise<Wallet | JsonRpcSigner> | (Wallet | JsonRpcSigner);

    constructor(
        signer: Wallet | JsonRpcSigner,
        chainId: Chain,
        signatureType?: SignatureType,
        funderAddress?: string,
        getSigner?: () => Promise<Wallet | JsonRpcSigner> | (Wallet | JsonRpcSigner)
    ) {
        this.signer = signer;
        this.chainId = chainId;
        this.signatureType = signatureType === undefined ? SignatureType.EOA : signatureType;
        this.funderAddress = funderAddress;
        this.getSigner = getSigner;
    }

    /**
     * Generate and sign a order
     */
    public async buildOrder(
        userOrder: UserOrder,
        options: CreateOrderOptions,
    ): Promise<SignedOrder> {
        const signer = await this.resolveSigner();
        return createOrder(
            signer,
            this.chainId,
            this.signatureType,
            this.funderAddress,
            userOrder,
            options,
        );
    }

    /**
     * Generate and sign a market order
     */
    public async buildMarketOrder(
        userMarketOrder: UserMarketOrder,
        options: CreateOrderOptions,
    ): Promise<SignedOrder> {
        const signer = await this.resolveSigner();
        return createMarketOrder(
            signer,
            this.chainId,
            this.signatureType,
            this.funderAddress,
            userMarketOrder,
            options,
        );
    }

    /** Unified getter: use fresh signer if available */
    private async resolveSigner(): Promise<Wallet | JsonRpcSigner> {
        if (this.getSigner) {
            const s = await this.getSigner();
            if (!s) throw new Error("getSigner() function returned undefined or null");
            return s;
        }
        return this.signer;
    }
}

