    const result = await this.get(`${this.host}${GET_NEG_RISK}`, {
        params: { token_id: tokenID },
    });
    if (result.error) {
        throw new Error(result.error);
    }
    this.negRisk[tokenID] = result.neg_risk as boolean;

    return this.negRisk[tokenID];
}

