    next_cursor = next_cursor || INITIAL_CURSOR;

    const _params: any = { ...params, next_cursor };

    const {
        data,
        ...rest
    }: {
        data: BuilderTrade[];
        next_cursor: string;
        limit: number;
        count: number;
    } = await this.get(`${this.host}${endpoint}`, {
        headers,
        params: _params,
    });

    return { trades: Array.isArray(data) ? [...data] : [], ...rest };
}

