  let decrypted = decipher.update(cipherData.encrypted, 'hex', 'utf8')
  decrypted += decipher.final('utf8')

  return decrypted
}

// Save builder config (encrypted private key)
export async function saveBuilderConfig(config) {
  ensureStorageDir()

