    println!("    Config:  {}", config::config_path()?.display());

    if !has_key {
        println!();
        println!("  ⚠ Back up your private key from the config file.");
        println!("    If lost, your funds cannot be recovered.");
    }

    Ok(address)
}

fn finish_setup(address: Address) -> Result<()> {
