    step_header(2, total, "Proxy Wallet");

    let proxy = derive_proxy_wallet(address, POLYGON);
    match proxy {
        Some(proxy) => {
            println!("  ✓ Proxy wallet derived");
            println!("    Proxy: {proxy}");
            println!("    Deposit USDC to this address to start trading.");
