   654→    public async getTrades(
   655→        params?: TradeParams,
   656→        only_first_page = false,
   657→        next_cursor?: string,
   658→    ): Promise<Trade[]> {
   659→        this.canL2Auth();
   660→
   661→        const endpoint = GET_TRADES;
   662→        const headerArgs = {
   663→            method: GET,
   664→            requestPath: endpoint,
   665→        };
   666→
   667→        const headers = await createL2Headers(
   668→            this.signer as Wallet | JsonRpcSigner,
   669→            this.creds as ApiKeyCreds,
   670→            headerArgs,
   671→            this.useServerTime ? await this.getServerTime() : undefined,
   672→        );
   673→
   674→        let results: Trade[] = [];
   675→        next_cursor = next_cursor || INITIAL_CURSOR;
   676→        while (next_cursor != END_CURSOR && (next_cursor === INITIAL_CURSOR || !only_first_page)) {
   677→            const _params: any = {
   678→                ...params,
   679→                next_cursor,
   680→            };
   681→            const response = await this.get(`${this.host}${endpoint}`, {
   682→                headers,
   683→                params: _params,
   684→            });
   685→            next_cursor = response.next_cursor;
   686→            results = [...results, ...response.data];
   687→        }
   688→        return results;
   689→    }
