   252→        let mut input = String::new();
   253→        io::stdin().lock().read_line(&mut input)?;
   254→        if !matches!(input.trim().to_lowercase().as_str(), "y" | "yes") {
   255→            println!("Aborted.");
   256→            return Ok(());
   257→        }
   258→    }
   259→
   260→    let path = config::config_path()?;
   261→    config::delete_config()?;
   262→
   263→    match output {
   264→        OutputFormat::Table => {
   265→            println!("Config deleted: {}", path.display());
