    57→fn prompt(msg: &str) -> Result<String> {
    58→    print!("{msg}");
    59→    io::stdout().flush()?;
    60→    let mut input = String::new();
    61→    io::stdin().lock().read_line(&mut input)?;
    62→    Ok(input.trim().to_string())
    63→}
    64→
    65→fn prompt_yn(msg: &str, default: bool) -> Result<bool> {
    66→    let hint = if default { "Y/n" } else { "y/N" };
    67→    let input = prompt(&format!("{msg} [{hint}] "))?;
    68→    Ok(match input.to_lowercase().as_str() {
    69→        "y" | "yes" => true,
    70→        "n" | "no" => false,
    71→        _ => default,
    72→    })
    73→}
