    80→pub fn execute() -> Result<()> {
    81→    print_banner();
    82→
    83→    let total = 4;
    84→
    85→    step_header(1, total, "Wallet");
    86→
    87→    let address = if config::config_exists() {
    88→        let (key, source) = config::resolve_key(None);
    89→        if let Some(k) = &key
    90→            && let Ok(signer) = LocalSigner::from_str(k)
    91→        {
    92→            let addr = signer.address();
    93→            println!("  ✓ Wallet already configured ({})", source.label());
    94→            println!("    Address: {addr}");
    95→            println!();
    96→
    97→            if !prompt_yn("  Reconfigure wallet?", false)? {
    98→                finish_setup(addr)?;
    99→                return Ok(());
   100→            }
   101→            println!();
   102→        }
   103→        setup_wallet()?
   104→    } else {
   105→        setup_wallet()?
   106→    };
   107→
   108→    println!();
   109→
   110→    finish_setup(address)
   111→}
   112→
   113→fn setup_wallet() -> Result<Address> {
   114→    let has_key = prompt_yn("  Do you have an existing private key?", false)?;
   115→
   116→    let (address, key_hex) = if has_key {
   117→        let key = prompt("  Enter private key: ")?;
   118→        let normalized = normalize_key(&key);
   119→        let signer = LocalSigner::from_str(&normalized)
   120→            .context("Invalid private key")?
   121→            .with_chain_id(Some(POLYGON));
   122→        (signer.address(), normalized)
   123→    } else {
   124→        let signer = LocalSigner::random().with_chain_id(Some(POLYGON));
   125→        let address = signer.address();
   126→        let bytes = signer.credential().to_bytes();
   127→        let mut hex = String::with_capacity(2 + bytes.len() * 2);
   128→        hex.push_str("0x");
   129→        for b in &bytes {
   130→            write!(hex, "{b:02x}").unwrap();
   131→        }
   132→        (address, hex)
   133→    };
   134→
   135→    config::save_wallet(&key_hex, POLYGON, config::DEFAULT_SIGNATURE_TYPE)?;
   136→
   137→    if has_key {
   138→        println!("  ✓ Wallet imported");
   139→    } else {
   140→        println!("  ✓ Wallet created");
   141→    }
   142→    println!("    Address: {address}");
   143→    println!("    Config:  {}", config::config_path()?.display());
   144→
   145→    if !has_key {
   146→        println!();
   147→        println!("  ⚠ Back up your private key from the config file.");
   148→        println!("    If lost, your funds cannot be recovered.");
   149→    }
   150→
   151→    Ok(address)
   152→}
   153→
   154→fn finish_setup(address: Address) -> Result<()> {
   155→    let total = 4;
   156→
   157→    step_header(2, total, "Proxy Wallet");
   158→
   159→    let proxy = derive_proxy_wallet(address, POLYGON);
   160→    match proxy {
   161→        Some(proxy) => {
   162→            println!("  ✓ Proxy wallet derived");
   163→            println!("    Proxy: {proxy}");
   164→            println!("    Deposit USDC to this address to start trading.");
   165→        }
   166→        None => {
   167→            println!("  ✗ Could not derive proxy wallet");
   168→            println!("    You may need to use --signature-type eoa");
   169→        }
   170→    }
   171→
   172→    println!();
   173→
   174→    step_header(3, total, "Fund Wallet");
   175→
   176→    let deposit_addr = proxy.unwrap_or(address);
   177→    println!("  ○ Deposit USDC to your wallet to start trading");
   178→    println!("    Run: polymarket bridge deposit {deposit_addr}");
   179→    println!("    Or transfer USDC directly on Polygon");
   180→
   181→    println!();
   182→
   183→    step_header(4, total, "Approve Contracts");
   184→
   185→    println!("  Run `polymarket approve set` to approve contracts for trading.");
   186→    println!("  Or `polymarket approve check` to see current approval status.");
   187→
   188→    println!();
   189→    println!("  ────────────────────────────────────");
   190→    println!("  ✓ Setup complete! You're ready to go.");
   191→    println!();
   192→    println!("  Next steps:");
   193→    println!("    polymarket shell              Interactive mode");
   194→    println!("    polymarket markets list        Browse markets");
   195→    println!("    polymarket clob book <token>   View order book");
   196→    println!();
   197→
   198→    Ok(())
   199→}
