     1→import type { Wallet } from "@ethersproject/wallet";
     2→import type { JsonRpcSigner } from "@ethersproject/providers";
     3→import { SignatureType } from "@polymarket/order-utils";
     4→import type { SignedOrder } from "@polymarket/order-utils";
     5→import { createMarketOrder, createOrder } from "./helpers.ts";
     6→import type { Chain, CreateOrderOptions, UserMarketOrder, UserOrder } from "../types.ts";
     7→
     8→export class OrderBuilder {
     9→    readonly signer: Wallet | JsonRpcSigner;
    10→
    11→    readonly chainId: Chain;
    12→
    13→    // Signature type used sign orders, defaults to EOA type
    14→    readonly signatureType: SignatureType;
    15→
    16→    // Address which holds funds to be used.
    17→    // Used for Polymarket proxy wallets and other smart contract wallets
    18→    // If not provided, funderAddress is the signer address
    19→    readonly funderAddress?: string;
    20→
    21→    /**
    22→     * Optional function to dynamically resolve the signer.
    23→     * If provided, this function will be called to obtain a fresh signer instance
    24→     * (e.g., for smart contract wallets or when the signer may change).
    25→     * Should return a Wallet or JsonRpcSigner, or a Promise resolving to one.
    26→     * If not provided, the static `signer` property is used.
    27→     */
    28→    private getSigner?: () => Promise<Wallet | JsonRpcSigner> | (Wallet | JsonRpcSigner);
    29→
    30→    constructor(
    31→        signer: Wallet | JsonRpcSigner,
    32→        chainId: Chain,
    33→        signatureType?: SignatureType,
    34→        funderAddress?: string,
    35→        getSigner?: () => Promise<Wallet | JsonRpcSigner> | (Wallet | JsonRpcSigner)
    36→    ) {
    37→        this.signer = signer;
    38→        this.chainId = chainId;
    39→        this.signatureType = signatureType === undefined ? SignatureType.EOA : signatureType;
    40→        this.funderAddress = funderAddress;
    41→        this.getSigner = getSigner;
    42→    }
    43→
    44→    /**
    45→     * Generate and sign a order
    46→     */
    47→    public async buildOrder(
    48→        userOrder: UserOrder,
    49→        options: CreateOrderOptions,
    50→    ): Promise<SignedOrder> {
    51→        const signer = await this.resolveSigner();
    52→        return createOrder(
    53→            signer,
    54→            this.chainId,
    55→            this.signatureType,
    56→            this.funderAddress,
    57→            userOrder,
    58→            options,
    59→        );
    60→    }
    61→
    62→    /**
    63→     * Generate and sign a market order
    64→     */
    65→    public async buildMarketOrder(
    66→        userMarketOrder: UserMarketOrder,
    67→        options: CreateOrderOptions,
    68→    ): Promise<SignedOrder> {
    69→        const signer = await this.resolveSigner();
    70→        return createMarketOrder(
    71→            signer,
    72→            this.chainId,
    73→            this.signatureType,
    74→            this.funderAddress,
    75→            userMarketOrder,
    76→            options,
    77→        );
    78→    }
    79→
    80→    /** Unified getter: use fresh signer if available */
    81→    private async resolveSigner(): Promise<Wallet | JsonRpcSigner> {
    82→        if (this.getSigner) {
    83→            const s = await this.getSigner();
    84→            if (!s) throw new Error("getSigner() function returned undefined or null");
    85→            return s;
    86→        }
    87→        return this.signer;
    88→    }
    89→}
