    65→export const getOrderRawAmounts = (
    66→    side: Side,
    67→    size: number,
    68→    price: number,
    69→    roundConfig: RoundConfig,
    70→): { side: UtilsSide; rawMakerAmt: number; rawTakerAmt: number } => {
    71→    const rawPrice = roundNormal(price, roundConfig.price);
    72→
    73→    if (side === Side.BUY) {
    74→        // force 2 decimals places
    75→        const rawTakerAmt = roundDown(size, roundConfig.size);
    76→
    77→        let rawMakerAmt = rawTakerAmt * rawPrice;
    78→        if (decimalPlaces(rawMakerAmt) > roundConfig.amount) {
    79→            rawMakerAmt = roundUp(rawMakerAmt, roundConfig.amount + 4);
    80→            if (decimalPlaces(rawMakerAmt) > roundConfig.amount) {
    81→                rawMakerAmt = roundDown(rawMakerAmt, roundConfig.amount);
    82→            }
    83→        }
    84→
    85→        return {
    86→            side: UtilsSide.BUY,
    87→            rawMakerAmt,
    88→            rawTakerAmt,
    89→        };
    90→    } else {
    91→        const rawMakerAmt = roundDown(size, roundConfig.size);
    92→
    93→        let rawTakerAmt = rawMakerAmt * rawPrice;
    94→        if (decimalPlaces(rawTakerAmt) > roundConfig.amount) {
    95→            rawTakerAmt = roundUp(rawTakerAmt, roundConfig.amount + 4);
    96→            if (decimalPlaces(rawTakerAmt) > roundConfig.amount) {
    97→                rawTakerAmt = roundDown(rawTakerAmt, roundConfig.amount);
    98→            }
    99→        }
   100→
   101→        return {
   102→            side: UtilsSide.SELL,
   103→            rawMakerAmt,
   104→            rawTakerAmt,
   105→        };
   106→    }
   107→};
