   320→/**
   321→ * calculateBuyMarketPrice calculates the market price to buy a $$ amount
   322→ * @param positions
   323→ * @param amountToMatch worth to buy
   324→ * @returns
   325→ */
   326→export const calculateBuyMarketPrice = (
   327→    positions: OrderSummary[],
   328→    amountToMatch: number,
   329→    orderType: OrderType,
   330→) => {
   331→    if (!positions.length) {
   332→        throw new Error("no match");
   333→    }
   334→    let sum = 0;
   335→    /*
   336→    Asks:
   337→    [
   338→        { price: '0.6', size: '100' },
   339→        { price: '0.55', size: '100' },
   340→        { price: '0.5', size: '100' }
   341→    ]
   342→    So, if the amount to match is $150 that will be reached at first position so price will be 0.6
   343→    */
   344→    for (let i = positions.length - 1; i >= 0; i--) {
   345→        const p = positions[i];
   346→        sum += parseFloat(p.size) * parseFloat(p.price);
   347→        if (sum >= amountToMatch) {
   348→            return parseFloat(p.price);
   349→        }
   350→    }
   351→    if (orderType === OrderType.FOK) {
   352→        throw new Error("no match");
   353→    }
   354→    return parseFloat(positions[0].price);
   355→};
   356→
   357→/**
   358→ * calculateSellMarketPrice calculates the market price to sell a shares
   359→ * @param positions
   360→ * @param amountToMatch sells to share
   361→ * @returns
   362→ */
   363→export const calculateSellMarketPrice = (
   364→    positions: OrderSummary[],
   365→    amountToMatch: number,
   366→    orderType: OrderType,
   367→) => {
   368→    if (!positions.length) {
   369→        throw new Error("no match");
   370→    }
   371→    let sum = 0;
   372→    /*
   373→    Bids:
   374→    [
   375→        { price: '0.4', size: '100' },
   376→        { price: '0.45', size: '100' },
   377→        { price: '0.5', size: '100' }
   378→    ]
   379→    So, if the amount to match is 300 that will be reached at the first position so price will be 0.4
   380→    */
   381→    for (let i = positions.length - 1; i >= 0; i--) {
   382→        const p = positions[i];
   383→        sum += parseFloat(p.size);
   384→        if (sum >= amountToMatch) {
   385→            return parseFloat(p.price);
   386→        }
   387→    }
   388→    if (orderType === OrderType.FOK) {
   389→        throw new Error("no match");
   390→    }
   391→    return parseFloat(positions[0].price);
   392→};
