     1→use std::fs;
     2→use std::path::PathBuf;
     3→
     4→use anyhow::{Context, Result};
     5→use serde::{Deserialize, Serialize};
     6→
     7→const ENV_VAR: &str = "POLYMARKET_PRIVATE_KEY";
     8→const SIG_TYPE_ENV_VAR: &str = "POLYMARKET_SIGNATURE_TYPE";
     9→pub const DEFAULT_SIGNATURE_TYPE: &str = "proxy";
    10→
    11→pub const NO_WALLET_MSG: &str =
    12→    "No wallet configured. Run `polymarket wallet create` or `polymarket wallet import <key>`";
    13→
    14→#[derive(Serialize, Deserialize)]
    15→pub struct Config {
    16→    pub private_key: String,
    17→    pub chain_id: u64,
    18→    #[serde(default = "default_signature_type")]
    19→    pub signature_type: String,
    20→}
    21→
    22→fn default_signature_type() -> String {
    23→    DEFAULT_SIGNATURE_TYPE.to_string()
    24→}
    25→
    26→pub enum KeySource {
    27→    Flag,
    28→    EnvVar,
    29→    ConfigFile,
    30→    None,
    31→}
    32→
    33→impl KeySource {
    34→    pub fn label(&self) -> &'static str {
    35→        match self {
    36→            Self::Flag => "--private-key flag",
    37→            Self::EnvVar => "POLYMARKET_PRIVATE_KEY env var",
    38→            Self::ConfigFile => "config file",
    39→            Self::None => "not configured",
    40→        }
    41→    }
    42→}
    43→
    44→fn config_dir() -> Result<PathBuf> {
    45→    let home = dirs::home_dir().context("Could not determine home directory")?;
    46→    Ok(home.join(".config").join("polymarket"))
    47→}
    48→
    49→pub fn config_path() -> Result<PathBuf> {
    50→    Ok(config_dir()?.join("config.json"))
    51→}
    52→
    53→pub fn config_exists() -> bool {
    54→    config_path().is_ok_and(|p| p.exists())
    55→}
    56→
    57→pub fn delete_config() -> Result<()> {
    58→    let dir = config_dir()?;
    59→    if dir.exists() {
    60→        fs::remove_dir_all(&dir).context("Failed to remove config directory")?;
    61→    }
    62→    Ok(())
    63→}
    64→
    65→pub fn load_config() -> Option<Config> {
    66→    let path = config_path().ok()?;
    67→    let data = fs::read_to_string(path).ok()?;
    68→    serde_json::from_str(&data).ok()
    69→}
    70→
    71→/// Priority: CLI flag > env var > config file > default ("proxy").
    72→pub fn resolve_signature_type(cli_flag: Option<&str>) -> String {
    73→    if let Some(st) = cli_flag {
    74→        return st.to_string();
    75→    }
    76→    if let Ok(st) = std::env::var(SIG_TYPE_ENV_VAR)
    77→        && !st.is_empty()
    78→    {
    79→        return st;
    80→    }
    81→    if let Some(config) = load_config() {
    82→        return config.signature_type;
    83→    }
    84→    DEFAULT_SIGNATURE_TYPE.to_string()
    85→}
    86→
    87→pub fn save_wallet(key: &str, chain_id: u64, signature_type: &str) -> Result<()> {
    88→    let dir = config_dir()?;
    89→    fs::create_dir_all(&dir).context("Failed to create config directory")?;
    90→
    91→    #[cfg(unix)]
    92→    {
    93→        use std::os::unix::fs::PermissionsExt;
    94→        fs::set_permissions(&dir, fs::Permissions::from_mode(0o700))?;
    95→    }
    96→
    97→    let config = Config {
    98→        private_key: key.to_string(),
    99→        chain_id,
   100→        signature_type: signature_type.to_string(),
   101→    };
   102→    let json = serde_json::to_string_pretty(&config)?;
   103→    let path = config_path()?;
   104→
   105→    #[cfg(unix)]
   106→    {
   107→        use std::io::Write as _;
   108→        use std::os::unix::fs::OpenOptionsExt;
   109→        let mut file = fs::OpenOptions::new()
   110→            .write(true)
   111→            .create(true)
   112→            .truncate(true)
   113→            .mode(0o600)
   114→            .open(&path)
   115→            .context("Failed to create config file")?;
   116→        file.write_all(json.as_bytes())
   117→            .context("Failed to write config file")?;
   118→    }
   119→
   120→    #[cfg(not(unix))]
   121→    {
   122→        fs::write(&path, &json).context("Failed to write config file")?;
   123→    }
   124→
   125→    Ok(())
   126→}
   127→
   128→/// Priority: CLI flag > env var > config file.
   129→pub fn resolve_key(cli_flag: Option<&str>) -> (Option<String>, KeySource) {
   130→    if let Some(key) = cli_flag {
   131→        return (Some(key.to_string()), KeySource::Flag);
   132→    }
   133→    if let Ok(key) = std::env::var(ENV_VAR)
   134→        && !key.is_empty()
   135→    {
   136→        return (Some(key), KeySource::EnvVar);
   137→    }
   138→    if let Some(config) = load_config() {
   139→        return (Some(config.private_key), KeySource::ConfigFile);
   140→    }
   141→    (None, KeySource::None)
   142→}
