    10→use crate::config;
    11→use crate::output::OutputFormat;
    12→
    13→#[derive(Args)]
    14→pub struct WalletArgs {
    15→    #[command(subcommand)]
    16→    pub command: WalletCommand,
    17→}
    18→
    19→#[derive(Subcommand)]
    20→pub enum WalletCommand {
    21→    /// Generate a new random wallet and save to config
    22→    Create {
    23→        /// Overwrite existing wallet
    24→        #[arg(long)]
    25→        force: bool,
    26→        /// Signature type: eoa, proxy (default), or gnosis-safe
    27→        #[arg(long, default_value = "proxy")]
    28→        signature_type: String,
    29→    },
    30→    /// Import an existing private key
    31→    Import {
    32→        /// Private key (hex, with or without 0x prefix)
    33→        key: String,
    34→        /// Overwrite existing wallet
    35→        #[arg(long)]
    36→        force: bool,
    37→        /// Signature type: eoa, proxy (default), or gnosis-safe
    38→        #[arg(long, default_value = "proxy")]
    39→        signature_type: String,
    40→    },
    41→    /// Show the address of the configured wallet
    42→    Address,
    43→    /// Show wallet info (address, config path, key source)
    44→    Show,
    45→    /// Delete all config and keys (fresh install)
    46→    Reset {
    47→        /// Skip confirmation prompt
    48→        #[arg(long)]
    49→        force: bool,
    50→    },
    51→}
    52→
    53→pub fn execute(
    54→    args: WalletArgs,
    55→    output: &OutputFormat,
    56→    private_key_flag: Option<&str>,
    57→) -> Result<()> {
    58→    match args.command {
    59→        WalletCommand::Create {
    60→            force,
    61→            signature_type,
    62→        } => cmd_create(output, force, &signature_type),
    63→        WalletCommand::Import {
    64→            key,
    65→            force,
    66→            signature_type,
    67→        } => cmd_import(&key, output, force, &signature_type),
    68→        WalletCommand::Address => cmd_address(output, private_key_flag),
    69→        WalletCommand::Show => cmd_show(output, private_key_flag),
    70→        WalletCommand::Reset { force } => cmd_reset(output, force),
    71→    }
    72→}
    73→
    74→fn guard_overwrite(force: bool) -> Result<()> {
    75→    if !force && config::config_exists() {
    76→        bail!(
    77→            "A wallet already exists at {}. Use --force to overwrite.",
    78→            config::config_path()?.display()
    79→        );
    80→    }
    81→    Ok(())
    82→}
    83→
    84→pub(crate) fn normalize_key(key: &str) -> String {
    85→    if key.starts_with("0x") || key.starts_with("0X") {
    86→        key.to_string()
    87→    } else {
    88→        format!("0x{key}")
    89→    }
    90→}
    91→
    92→fn cmd_create(output: &OutputFormat, force: bool, signature_type: &str) -> Result<()> {
    93→    guard_overwrite(force)?;
    94→
    95→    let signer = LocalSigner::random().with_chain_id(Some(POLYGON));
    96→    let address = signer.address();
    97→    let bytes = signer.credential().to_bytes();
    98→    let mut key_hex = String::with_capacity(2 + bytes.len() * 2);
    99→    key_hex.push_str("0x");
   100→    for b in &bytes {
   101→        write!(key_hex, "{b:02x}").unwrap();
   102→    }
   103→
   104→    config::save_wallet(&key_hex, POLYGON, signature_type)?;
   105→    let config_path = config::config_path()?;
   106→    let proxy_addr = derive_proxy_wallet(address, POLYGON);
   107→
   108→    match output {
   109→        OutputFormat::Json => {
   110→            println!(
   111→                "{}",
   112→                serde_json::json!({
   113→                    "address": address.to_string(),
   114→                    "proxy_address": proxy_addr.map(|a| a.to_string()),
   115→                    "signature_type": signature_type,
   116→                    "config_path": config_path.display().to_string(),
   117→                })
   118→            );
   119→        }
   120→        OutputFormat::Table => {
   121→            println!("Wallet created successfully!");
   122→            println!("Address:        {address}");
   123→            if let Some(proxy) = proxy_addr {
   124→                println!("Proxy wallet:   {proxy}");
   125→            }
   126→            println!("Signature type: {signature_type}");
   127→            println!("Config:         {}", config_path.display());
   128→            println!();
   129→            println!("IMPORTANT: Back up your private key from the config file.");
   130→            println!("           If lost, your funds cannot be recovered.");
   131→        }
   132→    }
   133→    Ok(())
   134→}
   135→
   136→fn cmd_import(key: &str, output: &OutputFormat, force: bool, signature_type: &str) -> Result<()> {
   137→    guard_overwrite(force)?;
   138→
   139→    let normalized = normalize_key(key);
   140→    let signer = LocalSigner::from_str(&normalized)
   141→        .context("Invalid private key")?
   142→        .with_chain_id(Some(POLYGON));
   143→    let address = signer.address();
   144→
   145→    config::save_wallet(&normalized, POLYGON, signature_type)?;
   146→    let config_path = config::config_path()?;
   147→    let proxy_addr = derive_proxy_wallet(address, POLYGON);
   148→
   149→    match output {
   150→        OutputFormat::Json => {
   151→            println!(
   152→                "{}",
   153→                serde_json::json!({
   154→                    "address": address.to_string(),
   155→                    "proxy_address": proxy_addr.map(|a| a.to_string()),
   156→                    "signature_type": signature_type,
   157→                    "config_path": config_path.display().to_string(),
   158→                })
   159→            );
   160→        }
   161→        OutputFormat::Table => {
   162→            println!("Wallet imported successfully!");
   163→            println!("Address:        {address}");
   164→            if let Some(proxy) = proxy_addr {
   165→                println!("Proxy wallet:   {proxy}");
   166→            }
   167→            println!("Signature type: {signature_type}");
   168→            println!("Config:         {}", config_path.display());
   169→        }
   170→    }
   171→    Ok(())
   172→}
   173→
   174→fn cmd_address(output: &OutputFormat, private_key_flag: Option<&str>) -> Result<()> {
   175→    let (key, _) = config::resolve_key(private_key_flag);
   176→    let key = key.ok_or_else(|| anyhow::anyhow!("{}", config::NO_WALLET_MSG))?;
   177→
   178→    let signer = LocalSigner::from_str(&key).context("Invalid private key")?;
   179→    let address = signer.address();
   180→
   181→    match output {
   182→        OutputFormat::Json => {
   183→            println!("{}", serde_json::json!({"address": address.to_string()}));
   184→        }
   185→        OutputFormat::Table => {
   186→            println!("{address}");
   187→        }
   188→    }
   189→    Ok(())
   190→}
   191→
   192→fn cmd_show(output: &OutputFormat, private_key_flag: Option<&str>) -> Result<()> {
   193→    let (key, source) = config::resolve_key(private_key_flag);
   194→    let signer = key.as_deref().and_then(|k| LocalSigner::from_str(k).ok());
   195→    let address = signer.as_ref().map(|s| s.address().to_string());
   196→    let proxy_addr = signer
   197→        .as_ref()
   198→        .and_then(|s| derive_proxy_wallet(s.address(), POLYGON))
   199→        .map(|a| a.to_string());
   200→
   201→    let sig_type = config::resolve_signature_type(None);
   202→    let config_path = config::config_path()?;
   203→
   204→    match output {
   205→        OutputFormat::Json => {
   206→            println!(
   207→                "{}",
   208→                serde_json::json!({
   209→                    "address": address,
   210→                    "proxy_address": proxy_addr,
   211→                    "signature_type": sig_type,
   212→                    "config_path": config_path.display().to_string(),
   213→                    "source": source.label(),
   214→                    "configured": address.is_some(),
   215→                })
   216→            );
   217→        }
   218→        OutputFormat::Table => {
