   113→fn setup_wallet() -> Result<Address> {
   114→    let has_key = prompt_yn("  Do you have an existing private key?", false)?;
   115→
   116→    let (address, key_hex) = if has_key {
   117→        let key = prompt("  Enter private key: ")?;
   118→        let normalized = normalize_key(&key);
   119→        let signer = LocalSigner::from_str(&normalized)
   120→            .context("Invalid private key")?
   121→            .with_chain_id(Some(POLYGON));
   122→        (signer.address(), normalized)
   123→    } else {
   124→        let signer = LocalSigner::random().with_chain_id(Some(POLYGON));
   125→        let address = signer.address();
   126→        let bytes = signer.credential().to_bytes();
   127→        let mut hex = String::with_capacity(2 + bytes.len() * 2);
   128→        hex.push_str("0x");
   129→        for b in &bytes {
   130→            write!(hex, "{b:02x}").unwrap();
   131→        }
   132→        (address, hex)
   133→    };
   134→
   135→    config::save_wallet(&key_hex, POLYGON, config::DEFAULT_SIGNATURE_TYPE)?;
   136→
   137→    if has_key {
   138→        println!("  ✓ Wallet imported");
   139→    } else {
   140→        println!("  ✓ Wallet created");
   141→    }
   142→    println!("    Address: {address}");
   143→    println!("    Config:  {}", config::config_path()?.display());
   144→
   145→    if !has_key {
   146→        println!();
   147→        println!("  ⚠ Back up your private key from the config file.");
   148→        println!("    If lost, your funds cannot be recovered.");
   149→    }
   150→
   151→    Ok(address)
   152→}
