   155→fn parse_u256_csv(s: &str) -> Result<Vec<U256>> {
   156→    s.split(',')
   157→        .map(|part| {
   158→            let trimmed = part.trim();
   159→            let val: u64 = trimmed
   160→                .parse()
   161→                .context(format!("Invalid value: {trimmed}"))?;
   162→            Ok(U256::from(val))
   163→        })
   164→        .collect()
   165→}
