   190→            amount,
   191→            collateral,
   192→            partition,
   193→            parent_collection,
   194→        } => {
   195→            let condition_id = super::parse_condition_id(&condition)?;
   196→            let usdc_amount = parse_usdc_amount(&amount)?;
