   210→                .condition_id(condition_id)
   211→                .partition(partition)
   212→                .amount(usdc_amount)
   213→                .build();
   214→
   215→            let resp = client
   216→                .split_position(&req)
   217→                .await
   218→                .context("Split position failed")?;
