    14→fn parse_signature_type(s: &str) -> SignatureType {
    15→    match s {
    16→        config::DEFAULT_SIGNATURE_TYPE => SignatureType::Proxy,
    17→        "gnosis-safe" => SignatureType::GnosisSafe,
    18→        _ => SignatureType::Eoa,
    19→    }
    20→}
    21→
    22→pub fn resolve_signer(
    23→    private_key: Option<&str>,
    24→) -> Result<impl polymarket_client_sdk::auth::Signer> {
    25→    let (key, _) = config::resolve_key(private_key);
    26→    let key = key.ok_or_else(|| anyhow::anyhow!("{}", config::NO_WALLET_MSG))?;
    27→    LocalSigner::from_str(&key)
    28→        .context("Invalid private key")
    29→        .map(|s| s.with_chain_id(Some(POLYGON)))
    30→}
    31→
    32→pub async fn authenticated_clob_client(
    33→    private_key: Option<&str>,
    34→    signature_type_flag: Option<&str>,
    35→) -> Result<clob::Client<Authenticated<Normal>>> {
    36→    let signer = resolve_signer(private_key)?;
    37→    authenticate_with_signer(&signer, signature_type_flag).await
    38→}
    39→
    40→pub async fn authenticate_with_signer(
    41→    signer: &(impl polymarket_client_sdk::auth::Signer + Sync),
    42→    signature_type_flag: Option<&str>,
    43→) -> Result<clob::Client<Authenticated<Normal>>> {
    44→    let sig_type = parse_signature_type(&config::resolve_signature_type(signature_type_flag));
    45→
    46→    clob::Client::default()
    47→        .authentication_builder(signer)
    48→        .signature_type(sig_type)
    49→        .authenticate()
    50→        .await
    51→        .context("Failed to authenticate with Polymarket CLOB")
    52→}
