}

// ─── CLOB API — authenticated endpoints ─────────────────────────────────────

// List open orders for the EOA
export async function getOpenOrders(privateKey) {
  const { client } = await getClobClient(privateKey)
  return client.getOpenOrders()
}

// Cancel a specific order by ID
export async function cancelOrder(orderId, privateKey) {
  const { client } = await getClobClient(privateKey)
  return client.cancelOrder({ orderID: orderId })
}

// ─── CLOB API — order creation + posting ────────────────────────────────────

// Create a signed order and POST to the CLOB via the official SDK.
// side: 'BUY' | 'SELL'
// orderType: 'GTC' (limit) | 'FOK' (market/fill-or-kill)
// size: number of outcome tokens (e.g. 10 = 10 YES tokens)
// price: probability 0-1 (e.g. 0.65)
// proxyWalletAddress: if set, order maker=proxy, signer=EOA, signatureType=POLY_PROXY
export async function createAndPostOrder({ tokenId, side, size, price, orderType = 'GTC', privateKey, proxyWalletAddress }) {
  const { client } = await getClobClient(privateKey, proxyWalletAddress)
  const order = await client.createOrder({
    tokenID: tokenId,
    price,
    size,
    side,
    feeRateBps: '0',
  })
  return client.postOrder(order, orderType)
}

// ─── Data API — positions ────────────────────────────────────────────────────

// Get open positions for a wallet address
export async function getPositions(address, limit = 20) {
  const res = await fetch(`${DATA_URL}/positions?user=${address}&limit=${limit}`)
  if (!res.ok) throw new Error(`Data API error: ${res.status} ${await res.text()}`)
  return res.json()
}

// ─── On-chain ops (viem, EOA-signed) — kept as low-level primitives ──────────
// Note: in the proxy wallet flow, on-chain ops are batched via executeViaProxyWallet above.
// These direct EOA functions remain available as fallback / for testing.

const ERC20_APPROVE_ABI = [{
  name: 'approve', type: 'function',
  inputs: [{ name: 'spender', type: 'address' }, { name: 'amount', type: 'uint256' }],
  outputs: [{ name: '', type: 'bool' }],
}]

