    outputs: [],
  },
]

// Neg Risk Adapter simplified splitPosition(bytes32 conditionId, uint256 amount)
const NEG_RISK_ADAPTER_ABI = [
  {
    name: 'splitPosition', type: 'function',
    inputs: [
