        erc20ApprovalTransaction(USDC_E, NEG_RISK_ADAPTER, MAX_UINT256),
        erc20ApprovalTransaction(USDC_E, NEG_RISK_CTF_EXCHANGE, MAX_UINT256),
        erc1155ApprovalTransaction(CTF, CTF_EXCHANGE),
        erc1155ApprovalTransaction(CTF, NEG_RISK_CTF_EXCHANGE),
        erc1155ApprovalTransaction(CTF, NEG_RISK_ADAPTER),
        ...sdkSplit(CTF, USDC_E, conditionId, 2, amountUnits.toString()),
      ]
    } else {
      // Regular market: USDC.e → CTF Exchange, CTF → CTF Exchange
      txBatch = [
        erc20ApprovalTransaction(USDC_E, CTF_EXCHANGE, MAX_UINT256),
        erc1155ApprovalTransaction(CTF, CTF_EXCHANGE),
        ...sdkSplit(CTF, USDC_E, conditionId, 2, amountUnits.toString()),
      ]
    }

    process.stderr.write(`[polymarket] Executing ${txBatch.length}-tx batch via proxy wallet...\n`)
    const executeTxHash = await executeViaProxyWallet(walletClient, publicClient, proxyWalletAddress, txBatch)
    process.stderr.write(`[polymarket] Proxy execute: ${executeTxHash}\n`)

    // Step 3: Post SELL order for unwanted side — maker=proxyWallet, signatureType=POLY_PROXY
    process.stderr.write(`[polymarket] Posting ${orderType} SELL order for unwanted ${outcomeArg === 'YES' ? 'NO' : 'YES'} tokens at ${sellPrice}...\n`)
    let orderResult
    try {
      orderResult = await createAndPostOrder({
        tokenId: unwantedTokenId,
        side: 'SELL',
        size: amountUsd,
        price: sellPrice,
        orderType,
        privateKey,
        proxyWalletAddress,
      })
    } catch (orderErr) {
      // Don't fail the whole command — split succeeded, tokens are in proxy wallet
      console.log(JSON.stringify({
        ok: true,
        conditionId,
        question: market.question,
        outcome: outcomeArg,
        amountUsd,
        proxyWalletAddress,
        fundTxHash: fundResult.txHash,
        executeTxHash,
        orderId: null,
        orderError: orderErr.message,
        note: `Split succeeded — ${outcomeArg} tokens held in proxy wallet ${proxyWalletAddress}. SELL order failed. Sell manually at polymarket.com`,
      }, null, 2))
      return
    }

    console.log(JSON.stringify({
      ok: true,
      conditionId,
      question: market.question,
      outcome: outcomeArg,
      amountUsd,
      effectivePrice: wantedPrice,
      proxyWalletAddress,
      signerAddress: account.address,
      fundTxHash: fundResult.txHash,
      executeTxHash,
      orderId: orderResult?.orderId || orderResult?.orderID || orderResult?.id || null,
      orderType,
      sellPrice,
      note: `${outcomeArg} position opened via proxy wallet. Unwanted side sell order posted.`,
    }, null, 2))

  } catch (err) {
    console.error(JSON.stringify({ ok: false, error: err.message, stack: err.stack }, null, 2))
    process.exit(1)
  }
}

// ─── polygon-agent polymarket positions ──────────────────────────────────────
// List open positions for the smart wallet address
// Options: --wallet <name>

export async function polymarketPositions() {
  const args = process.argv.slice(2)
  const walletName = getArg(args, '--wallet') || 'main'

  try {
    const session = await loadWalletSession(walletName)
    if (!session) throw new Error(`Wallet not found: ${walletName}`)

