// Create a signed limit order and POST to the CLOB via the official SDK.
// side: 'BUY' | 'SELL'
// orderType: 'GTC' (limit) | 'FOK' (market/fill-or-kill)
// size: number of outcome tokens (e.g. 10 = 10 YES tokens)
// price: probability 0-1 (e.g. 0.65)
// proxyWalletAddress: if set, order maker=proxy, signer=EOA, signatureType=POLY_PROXY
export async function createAndPostOrder({ tokenId, side, size, price, orderType = 'GTC', privateKey, proxyWalletAddress }) {
  const { client } = await getClobClient(privateKey, proxyWalletAddress)
  const order = await client.createOrder({
    tokenID: tokenId,
    price,
    size,
    side,
    feeRateBps: '0',
  })
  return client.postOrder(order, orderType)
}

// Create a signed market order and POST to the CLOB via the official SDK.
// side: 'BUY' | 'SELL'
// orderType: 'FOK' (fill-or-kill, default) | 'FAK' (fill-and-kill, allows partial fill)
// amount:
//   - BUY side: USDC amount to spend (e.g. 10 = spend $10 USDC to buy tokens)
//   - SELL side: number of tokens to sell (e.g. 10 = sell 10 YES tokens)
// proxyWalletAddress: if set, order maker=proxy, signer=EOA, signatureType=POLY_PROXY
export async function createAndPostMarketOrder({ tokenId, side, amount, orderType = 'FOK', privateKey, proxyWalletAddress }) {
  const { client } = await getClobClient(privateKey, proxyWalletAddress)
  const order = await client.createMarketOrder({
    tokenID: tokenId,
    side,
    amount,
    orderType,
    feeRateBps: '0',
  })
  return client.postOrder(order, orderType)
}

