// ─── polygon-agent polymarket clob-buy <conditionId> YES|NO <amount> ────────
// Buy YES or NO tokens directly via a CLOB market BUY order — no split required.
// USDC.e flows from the proxy wallet to buy the tokens at market price.
// The proxy wallet must already hold USDC.e and have USDC.e approved for CTF_EXCHANGE.
// Use `polymarket buy` (split flow) the first time to set up approvals, or
// run `polymarket buy --broadcast` once to initialize the proxy wallet approvals.
//
// Options:
//   --wallet <name>     default: main
//   --price <0-1>       limit price (GTC); omit for market order (FOK)
//   --fak               use FAK (fill-and-kill, allows partial fill) instead of FOK
//   --broadcast         execute (dry-run without)

export async function polymarketClobBuy() {
  const args = process.argv.slice(2)
  const conditionId = process.argv[4]
  const outcomeArg  = (process.argv[5] || '').toUpperCase()
  const amountArg   = process.argv[6]
  const walletName  = getArg(args, '--wallet') || 'main'
  const priceArg    = getArg(args, '--price')
  const useFak      = hasFlag(args, '--fak')
  const broadcast   = hasFlag(args, '--broadcast')

  if (!conditionId || !outcomeArg || !amountArg) {
    console.error(JSON.stringify({
      ok: false,
      error: 'Usage: polymarket clob-buy <conditionId> YES|NO <usdcAmount> [--price <0-1>] [--fak] [--wallet <n>] [--broadcast]'
    }, null, 2))
    process.exit(1)
  }

  if (!['YES', 'NO'].includes(outcomeArg)) {
    console.error(JSON.stringify({ ok: false, error: 'Outcome must be YES or NO' }, null, 2))
    process.exit(1)
  }

  const amountUsd = Number(amountArg)
  if (!amountUsd || amountUsd <= 0) {
    console.error(JSON.stringify({ ok: false, error: 'Amount must be a positive number (USDC to spend)' }, null, 2))
    process.exit(1)
  }

  try {
    const market = await getMarket(conditionId)
    const tokenId = outcomeArg === 'YES' ? market.yesTokenId : market.noTokenId
    if (!tokenId) throw new Error(`Market ${conditionId} has no tokenIds (may be closed or invalid)`)

    const currentPrice = outcomeArg === 'YES' ? market.yesPrice : market.noPrice

    // Dry-run
    if (!broadcast) {
      let proxyWalletAddress = null
      try {
        const builderConfig = await loadBuilderConfig()
        if (builderConfig?.privateKey) {
          const { privateKeyToAccount } = await import('viem/accounts')
          proxyWalletAddress = await getPolymarketProxyWalletAddress(privateKeyToAccount(builderConfig.privateKey).address)
        }
      } catch (_) {}

      console.log(JSON.stringify({
        ok: true,
        dryRun: true,
        conditionId,
        question: market.question,
        outcome: outcomeArg,
        tokenId,
        currentPrice,
        amountUsd,
        orderType: priceArg ? 'GTC' : (useFak ? 'FAK' : 'FOK'),
        price: priceArg ? Number(priceArg) : 'market',
        proxyWalletAddress,
        note: 'Direct CLOB BUY — no split. Proxy wallet USDC.e must be pre-approved. Re-run with --broadcast.',
      }, null, 2))
      return
    }

    const builderConfig = await loadBuilderConfig()
    if (!builderConfig?.privateKey) throw new Error('Builder EOA not found. Run: polygon-agent setup')

    const { privateKeyToAccount } = await import('viem/accounts')
    const account = privateKeyToAccount(builderConfig.privateKey)
    const proxyWalletAddress = await getPolymarketProxyWalletAddress(account.address)
    process.stderr.write(`[polymarket] CLOB BUY ${amountUsd} USDC → ${outcomeArg} via proxy wallet ${proxyWalletAddress}\n`)

    let orderResult
    if (priceArg) {
      // Limit order (GTC)
      const estimatedShares = amountUsd / Number(priceArg)
      orderResult = await createAndPostOrder({
        tokenId,
        side: 'BUY',
        size: estimatedShares,
        price: Number(priceArg),
        orderType: 'GTC',
        privateKey: builderConfig.privateKey,
        proxyWalletAddress,
      })
    } else {
      // Market order (FOK or FAK)
      const orderType = useFak ? 'FAK' : 'FOK'
      orderResult = await createAndPostMarketOrder({
        tokenId,
        side: 'BUY',
        amount: amountUsd,
        orderType,
        privateKey: builderConfig.privateKey,
        proxyWalletAddress,
      })
    }

    console.log(JSON.stringify({
      ok: true,
      conditionId,
      question: market.question,
      outcome: outcomeArg,
      amountUsd,
      currentPrice,
      proxyWalletAddress,
      signerAddress: account.address,
      orderId: orderResult?.orderId || orderResult?.orderID || orderResult?.id || null,
      orderStatus: orderResult?.status || null,
    }, null, 2))

  } catch (err) {
    console.error(JSON.stringify({ ok: false, error: err.message, stack: err.stack }, null, 2))
    process.exit(1)
  }
}

// ─── polygon-agent polymarket sell <conditionId> YES|NO <shares> ─────────────
// Sell YES or NO tokens you hold in the proxy wallet via a CLOB SELL order.
// No on-chain ops needed — tokens leave the proxy wallet, USDC.e arrives.
//
// Options:
//   --price <0-1>       limit price (GTC); omit for market order (FOK)
//   --fak               use FAK (fill-and-kill, allows partial fill) instead of FOK
//   --broadcast         execute (dry-run without)

export async function polymarketSell() {
  const args = process.argv.slice(2)
  const conditionId = process.argv[4]
  const outcomeArg  = (process.argv[5] || '').toUpperCase()
  const sharesArg   = process.argv[6]
  const priceArg    = getArg(args, '--price')
  const useFak      = hasFlag(args, '--fak')
  const broadcast   = hasFlag(args, '--broadcast')

  if (!conditionId || !outcomeArg || !sharesArg) {
    console.error(JSON.stringify({
      ok: false,
      error: 'Usage: polymarket sell <conditionId> YES|NO <shares> [--price <0-1>] [--fak] [--broadcast]'
    }, null, 2))
    process.exit(1)
  }

  if (!['YES', 'NO'].includes(outcomeArg)) {
    console.error(JSON.stringify({ ok: false, error: 'Outcome must be YES or NO' }, null, 2))
    process.exit(1)
  }

  const shares = Number(sharesArg)
  if (!shares || shares <= 0) {
    console.error(JSON.stringify({ ok: false, error: 'Shares must be a positive number' }, null, 2))
    process.exit(1)
  }

  try {
    const market = await getMarket(conditionId)
    const tokenId = outcomeArg === 'YES' ? market.yesTokenId : market.noTokenId
    if (!tokenId) throw new Error(`Market ${conditionId} has no tokenIds (may be closed or invalid)`)

    const currentPrice = outcomeArg === 'YES' ? market.yesPrice : market.noPrice
    const estimatedUsd = shares * (currentPrice || 0)

    // Dry-run
    if (!broadcast) {
      let proxyWalletAddress = null
      try {
        const builderConfig = await loadBuilderConfig()
        if (builderConfig?.privateKey) {
          const { privateKeyToAccount } = await import('viem/accounts')
          proxyWalletAddress = await getPolymarketProxyWalletAddress(privateKeyToAccount(builderConfig.privateKey).address)
        }
      } catch (_) {}

      console.log(JSON.stringify({
        ok: true,
        dryRun: true,
        conditionId,
        question: market.question,
        outcome: outcomeArg,
        tokenId,
        shares,
        currentPrice,
        estimatedUsd: Math.round(estimatedUsd * 100) / 100,
        orderType: priceArg ? 'GTC' : (useFak ? 'FAK' : 'FOK'),
        price: priceArg ? Number(priceArg) : 'market',
        proxyWalletAddress,
        note: 'Direct CLOB SELL of existing position. Tokens must be in proxy wallet. Re-run with --broadcast.',
      }, null, 2))
      return
    }

    const builderConfig = await loadBuilderConfig()
    if (!builderConfig?.privateKey) throw new Error('Builder EOA not found. Run: polygon-agent setup')

    const { privateKeyToAccount } = await import('viem/accounts')
    const account = privateKeyToAccount(builderConfig.privateKey)
    const proxyWalletAddress = await getPolymarketProxyWalletAddress(account.address)
    process.stderr.write(`[polymarket] CLOB SELL ${shares} ${outcomeArg} tokens via proxy wallet ${proxyWalletAddress}\n`)

    let orderResult
    if (priceArg) {
      // Limit order (GTC)
      orderResult = await createAndPostOrder({
        tokenId,
        side: 'SELL',
        size: shares,
        price: Number(priceArg),
        orderType: 'GTC',
        privateKey: builderConfig.privateKey,
        proxyWalletAddress,
      })
    } else {
      // Market order (FOK or FAK)
      const orderType = useFak ? 'FAK' : 'FOK'
      orderResult = await createAndPostMarketOrder({
        tokenId,
        side: 'SELL',
        amount: shares,
        orderType,
        privateKey: builderConfig.privateKey,
        proxyWalletAddress,
      })
    }

    console.log(JSON.stringify({
      ok: true,
      conditionId,
      question: market.question,
      outcome: outcomeArg,
      shares,
      currentPrice,
      estimatedUsd: Math.round(estimatedUsd * 100) / 100,
      proxyWalletAddress,
      signerAddress: account.address,
      orderId: orderResult?.orderId || orderResult?.orderID || orderResult?.id || null,
      orderStatus: orderResult?.status || null,
    }, null, 2))

  } catch (err) {
    console.error(JSON.stringify({ ok: false, error: err.message, stack: err.stack }, null, 2))
    process.exit(1)
  }
}

