toolUseResult.originalFile:
// Polymarket CLI commands
// All commands follow the existing pattern: getArg, JSON output, --broadcast for write ops
//
// Architecture: Sequence smart wallet → Polymarket proxy wallet → CLOB
// - Sequence smart wallet funds the proxy wallet (USDC.e transfer)
// - EOA calls proxy.execute([approve, split]) in one tx
// - CLOB orders: maker=proxyWallet, signer=EOA, signatureType=POLY_PROXY

import { loadWalletSession, loadBuilderConfig } from '../../lib/storage.mjs'
import { runDappClientTx } from '../../lib/dapp-client.mjs'
import { getArg, hasFlag } from '../../lib/utils.mjs'
import {
  getMarkets, getMarket,
  getClobPrice,
  getOpenOrders, cancelOrder,
  createAndPostOrder, createAndPostMarketOrder,
  getPolymarketProxyWalletAddress, executeViaProxyWallet,
  getPositions,
  USDC_E, CTF, CTF_EXCHANGE, NEG_RISK_CTF_EXCHANGE, NEG_RISK_ADAPTER,
} from '../../lib/polymarket.mjs'

// ─── polygon-agent polymarket markets ────────────────────────────────────────
// List active markets sorted by 24h volume
// Options: --search <query>, --limit <n>, --offset <n>

export async function polymarketMarkets() {
  const args = process.argv.slice(2)
  const search = getArg(args, '--search')
  const limit  = Number(getArg(args, '--limit')  || 20)
  const offset = Number(getArg(args, '--offset') || 0)

  try {
    const markets = await getMarkets({ search, limit, offset })
    console.log(JSON.stringify({ ok: true, count: markets.length, markets }, null, 2))
  } catch (err) {
    console.error(JSON.stringify({ ok: false, error: err.message }, null, 2))
    process.exit(1)
  }
}

// ─── polygon-agent polymarket market <conditionId> ───────────────────────────
// Get a single market by conditionId

export async function polymarketMarket() {
  const conditionId = process.argv[4]
  if (!conditionId) {
    console.error(JSON.stringify({ ok: false, error: 'Usage: polymarket market <conditionId>' }, null, 2))
    process.exit(1)
  }

  try {
    const market = await getMarket(conditionId)
    console.log(JSON.stringify({ ok: true, market }, null, 2))
  } catch (err) {
    console.error(JSON.stringify({ ok: false, error: err.message }, null, 2))
    process.exit(1)
  }
}

// ─── polygon-agent polymarket proxy-wallet ───────────────────────────────────
// Show the Polymarket proxy wallet address for the builder EOA
// This is where USDC.e must sit for CLOB trading

export async function polymarketProxyWallet() {
  try {
    const builderConfig = await loadBuilderConfig()
    if (!builderConfig?.privateKey) throw new Error('Builder EOA not found. Run: polygon-agent setup')

    const { privateKeyToAccount } = await import('viem/accounts')
    const account = privateKeyToAccount(builderConfig.privateKey)
    const proxyWalletAddress = await getPolymarketProxyWalletAddress(account.address)

    console.log(JSON.stringify({
      ok: true,
      eoaAddress: account.address,
      proxyWalletAddress,
      note: 'Fund proxyWalletAddress with USDC.e on Polygon to enable CLOB trading.',
    }, null, 2))
  } catch (err) {
    console.error(JSON.stringify({ ok: false, error: err.message }, null, 2))
    process.exit(1)
  }
}

// ─── polygon-agent polymarket buy <conditionId> YES|NO <amount> ──────────────
// Buy an outcome via the Polymarket proxy wallet flow:
//   1. Smart wallet → fund proxy wallet with USDC.e
//   2. EOA: proxy.execute([approveUSDCe, approveCtf, splitPosition]) — one tx
//   3. EOA: post SELL order for unwanted side (FOK market or GTC limit)
//      — maker=proxyWallet, signer=EOA, signatureType=POLY_PROXY
//
// Options:
//   --wallet <name>     default: main
//   --price <0-1>       limit price for selling unwanted side (default: market order FOK)
//   --broadcast         execute (dry-run without)

export async function polymarketBuy() {
  const args = process.argv.slice(2)
  const conditionId = process.argv[4]
  const outcomeArg  = (process.argv[5] || '').toUpperCase()
  const amountArg   = process.argv[6]
  const walletName  = getArg(args, '--wallet') || 'main'
  const priceArg    = getArg(args, '--price')
  const broadcast   = hasFlag(args, '--broadcast')
  const skipFund    = hasFlag(args, '--skip-fund')

  if (!conditionId || !outcomeArg || !amountArg) {
    console.error(JSON.stringify({
      ok: false,
      error: 'Usage: polymarket buy <conditionId> YES|NO <amount> [--price <0-1>] [--wallet <n>] [--broadcast]'
    }, null, 2))
    process.exit(1)
  }

  if (!['YES', 'NO'].includes(outcomeArg)) {
    console.error(JSON.stringify({ ok: false, error: 'Outcome must be YES or NO' }, null, 2))
    process.exit(1)
  }

  const amountUsd = Number(amountArg)
  if (!amountUsd || amountUsd <= 0) {
    console.error(JSON.stringify({ ok: false, error: 'Amount must be a positive number' }, null, 2))
    process.exit(1)
  }

  try {
    // Load market info
    const market = await getMarket(conditionId)
    const wantedTokenId   = outcomeArg === 'YES' ? market.yesTokenId : market.noTokenId
    const unwantedTokenId = outcomeArg === 'YES' ? market.noTokenId  : market.yesTokenId

    if (!wantedTokenId || !unwantedTokenId) {
      throw new Error(`Market ${conditionId} has no tokenIds (may be closed or invalid)`)
    }

    // Get current price of wanted outcome
    const wantedPrice = outcomeArg === 'YES' ? market.yesPrice : market.noPrice

    // Determine sell price for unwanted side
    let sellPrice
    let orderType
    if (priceArg) {
      sellPrice = Number(priceArg)
      orderType = 'GTC'
    } else {
      // Market order: sell at 90% of current bid for unwanted side
      const unwantedBid = await getClobPrice(unwantedTokenId, 'BUY')
      sellPrice = Math.max(0.01, unwantedBid * 0.9)
      orderType = 'FOK'
    }

    // Amount in micro-USDC (6 decimals)
    const amountUnits = BigInt(Math.round(amountUsd * 1e6))

    // Dry-run: show plan without executing
    if (!broadcast) {
      // Compute proxy wallet address for display (needs builder config)
      let proxyWalletAddress = null
      try {
        const builderConfig = await loadBuilderConfig()
        if (builderConfig?.privateKey) {
          const { privateKeyToAccount } = await import('viem/accounts')
          const account = privateKeyToAccount(builderConfig.privateKey)
          proxyWalletAddress = await getPolymarketProxyWalletAddress(account.address)
        }
      } catch (_) {}

      console.log(JSON.stringify({
        ok: true,
        dryRun: true,
        conditionId,
        question: market.question,
        outcome: outcomeArg,
        wantedTokenId,
        unwantedTokenId,
        wantedCurrentPrice: wantedPrice,
        amountUsd,
        splitAmountUnits: amountUnits.toString(),
        sellUnwantedAt: sellPrice,
        orderType,
        negRisk: market.negRisk,
        proxyWalletAddress,
        flow: [
          'Smart wallet → fund proxy wallet with USDC.e',
          'EOA → proxy.execute([approveUSDCe, approveCtf, splitPosition])',
          `EOA → CLOB SELL order (maker=proxyWallet, signatureType=POLY_PROXY)`,
        ],
        note: 'Re-run with --broadcast to execute.',
      }, null, 2))
      return
    }

    // Load credentials
    const [session, builderConfig] = await Promise.all([
      loadWalletSession(walletName),
      loadBuilderConfig(),
    ])
    if (!session) throw new Error(`Wallet not found: ${walletName}`)
    if (!builderConfig?.privateKey) throw new Error('Builder EOA not found. Run: polygon-agent setup')

    const privateKey = builderConfig.privateKey
    const { privateKeyToAccount } = await import('viem/accounts')
    const { createWalletClient, createPublicClient, http } = await import('viem')
    const { polygon } = await import('viem/chains')

    const account      = privateKeyToAccount(privateKey)
    const walletClient = createWalletClient({ account, chain: polygon, transport: http() })
    const publicClient = createPublicClient({ chain: polygon, transport: http() })

    // Compute proxy wallet address
    const proxyWalletAddress = await getPolymarketProxyWalletAddress(account.address)
    process.stderr.write(`[polymarket] EOA: ${account.address}\n`)
    process.stderr.write(`[polymarket] Proxy wallet: ${proxyWalletAddress}\n`)

    // Step 1: Fund proxy wallet from Sequence smart wallet (transfer USDC.e to proxyWallet)
    let fundResult = { txHash: null }
    if (skipFund) {
      process.stderr.write(`[polymarket] --skip-fund: using existing proxy wallet balance\n`)
    } else {
      process.stderr.write(`[polymarket] Funding proxy wallet ${proxyWalletAddress} with ${amountUsd} USDC.e...\n`)
      const pad = (hex, n = 64) => String(hex).replace(/^0x/, '').padStart(n, '0')
      const transferData = '0xa9059cbb' + pad(proxyWalletAddress) + pad('0x' + amountUnits.toString(16))
      fundResult = await runDappClientTx({
        walletName,
        chainId: 137,
        transactions: [{ to: USDC_E, value: 0n, data: transferData }],
        broadcast: true,
        preferNativeFee: false,
      })
      process.stderr.write(`[polymarket] Funded: ${fundResult.txHash}\n`)
    }

    // Step 2: Build transaction batch via @polymarket/sdk and execute through proxy wallet
    // All ops happen FROM the proxy wallet in a single tx — EOA pays gas
    const { splitPosition: sdkSplit, erc20ApprovalTransaction, erc1155ApprovalTransaction } = await import('@polymarket/sdk')
    const MAX_UINT256 = '0xffffffffffffffffffffffffffffffffffffffffffffffffffffffffffffffff'

    let txBatch
    if (market.negRisk) {
      // Neg risk: USDC.e → NegRiskAdapter, CTF → NegRiskExchange + NegRiskAdapter
      // splitPosition via NegRiskAdapter (2-outcome market = 2 slots)
      txBatch = [
        erc20ApprovalTransaction(USDC_E, NEG_RISK_ADAPTER, MAX_UINT256),
        erc20ApprovalTransaction(USDC_E, NEG_RISK_CTF_EXCHANGE, MAX_UINT256),
        erc1155ApprovalTransaction(CTF, CTF_EXCHANGE),
        erc1155ApprovalTransaction(CTF, NEG_RISK_CTF_EXCHANGE),
        erc1155ApprovalTransaction(CTF, NEG_RISK_ADAPTER),
        ...sdkSplit(CTF, USDC_E, conditionId, 2, amountUnits.toString()),
      ]
    } else {
      // Regular market: USDC.e → CTF Exchange, CTF → CTF Exchange
      txBatch = [
        erc20ApprovalTransaction(USDC_E, CTF_EXCHANGE, MAX_UINT256),
        erc1155ApprovalTransaction(CTF, CTF_EXCHANGE),
        ...sdkSplit(CTF, USDC_E, conditionId, 2, amountUnits.toString()),
      ]
    }

    process.stderr.write(`[polymarket] Executing ${txBatch.length}-tx batch via proxy wallet...\n`)
    const executeTxHash = await executeViaProxyWallet(walletClient, publicClient, proxyWalletAddress, txBatch)
    process.stderr.write(`[polymarket] Proxy execute: ${executeTxHash}\n`)

    // Step 3: Post SELL order for unwanted side — maker=proxyWallet, signatureType=POLY_PROXY
    process.stderr.write(`[polymarket] Posting ${orderType} SELL order for unwanted ${outcomeArg === 'YES' ? 'NO' : 'YES'} tokens at ${sellPrice}...\n`)
    let orderResult
    try {
      orderResult = await createAndPostOrder({
        tokenId: unwantedTokenId,
        side: 'SELL',
        size: amountUsd,
        price: sellPrice,
        orderType,
        privateKey,
        proxyWalletAddress,
      })
    } catch (orderErr) {
      // Don't fail the whole command — split succeeded, tokens are in proxy wallet
      console.log(JSON.stringify({
        ok: true,
        conditionId,
        question: market.question,
        outcome: outcomeArg,
        amountUsd,
        proxyWalletAddress,
        fundTxHash: fundResult.txHash,
        executeTxHash,
        orderId: null,
        orderError: orderErr.message,
        note: `Split succeeded — ${outcomeArg} tokens held in proxy wallet ${proxyWalletAddress}. SELL order failed. Sell manually at polymarket.com`,
      }, null, 2))
      return
    }

    console.log(JSON.stringify({
      ok: true,
      conditionId,
      question: market.question,
      outcome: outcomeArg,
      amountUsd,
      effectivePrice: wantedPrice,
      proxyWalletAddress,
      signerAddress: account.address,
      fundTxHash: fundResult.txHash,
      executeTxHash,
      orderId: orderResult?.orderId || orderResult?.orderID || orderResult?.id || null,
      orderType,
      sellPrice,
      note: `${outcomeArg} position opened via proxy wallet. Unwanted side sell order posted.`,
    }, null, 2))

  } catch (err) {
    console.error(JSON.stringify({ ok: false, error: err.message, stack: err.stack }, null, 2))
    process.exit(1)
  }
}

// ─── polygon-agent polymarket positions ──────────────────────────────────────
// List open positions for the smart wallet address
// Options: --wallet <name>

export async function polymarketPositions() {
  const args = process.argv.slice(2)
  const walletName = getArg(args, '--wallet') || 'main'

  try {
    const session = await loadWalletSession(walletName)
    if (!session) throw new Error(`Wallet not found: ${walletName}`)

    const positions = await getPositions(session.walletAddress)
    console.log(JSON.stringify({
      ok: true,
      walletAddress: session.walletAddress,
      count: Array.isArray(positions) ? positions.length : 0,
      positions,
    }, null, 2))
  } catch (err) {
    console.error(JSON.stringify({ ok: false, error: err.message }, null, 2))
    process.exit(1)
  }
}

// ─── polygon-agent polymarket orders ─────────────────────────────────────────
// List open CLOB orders for the builder EOA
// Options: --wallet <name> (unused but accepted for consistency)

export async function polymarketOrders() {
  try {
    const builderConfig = await loadBuilderConfig()
    if (!builderConfig?.privateKey) throw new Error('Builder EOA not found. Run: polygon-agent setup')

    const orders = await getOpenOrders(builderConfig.privateKey)

    console.log(JSON.stringify({
      ok: true,
      count: Array.isArray(orders) ? orders.length : 0,
      orders,
    }, null, 2))
  } catch (err) {
    console.error(JSON.stringify({ ok: false, error: err.message }, null, 2))
    process.exit(1)
  }
}

// ─── polygon-agent polymarket cancel <orderId> ───────────────────────────────
// Cancel an open CLOB order by ID

export async function polymarketCancel() {
  const orderId = process.argv[4]
  if (!orderId) {
    console.error(JSON.stringify({ ok: false, error: 'Usage: polymarket cancel <orderId>' }, null, 2))
    process.exit(1)
  }

  try {
    const builderConfig = await loadBuilderConfig()
    if (!builderConfig?.privateKey) throw new Error('Builder EOA not found. Run: polygon-agent setup')

    const result = await cancelOrder(orderId, builderConfig.privateKey)

    console.log(JSON.stringify({
      ok: true,
      orderId,
      result,
    }, null, 2))
  } catch (err) {
    console.error(JSON.stringify({ ok: false, error: err.message }, null, 2))
    process.exit(1)
  }
}

